                    const filteredItems = data.data.items.filter(
                        (item: PortfolioItem) => item.type !== 'Our Product'
                    )
                    setItems(filteredItems)
                }
            } catch (error) {
                console.error('Failed to fetch portfolio:', error)
            } finally {
                setIsLoading(false)
            }
        }
        fetchPortfolio()
    }, [])

